)
headers = {"Authorization": f"Bearer {token}"}

def fetch_with_cursor(base_url: str, headers: dict) -> list[dict]:
    all_records = []
    next_cursor = None

    while True:
        params = {"limit": 100}
        if next_cursor:
            params["cursor"] = next_cursor

        response = requests.get(base_url, headers=headers, params=params, timeout=10)
        response.raise_for_status()
        body = response.json()

        all_records.extend(body.get("results", []))

        next_cursor = body.get("next_cursor")
        if not next_cursor:
            break

    return all_records

def fetch_github_style(url: str, headers: dict) -> list[dict]:
    all_records = []

    while url:
        response = requests.get(url, headers=headers, timeout=10)
        response.raise_for_status()
        all_records.extend(response.json())

        # Parse the Link header for the "next" URL
        link_header = response.headers.get("Link", "")
        url = parse_next_link(link_header)

    return all_records

def parse_next_link(link_header: str) -> str | None:
    """Extract the 'next' URL from a Link header."""
    for part in link_header.split(","):
        url_part, rel_part = part.strip().split(";")
        if 'rel="next"' in rel_part:
            return url_part.strip().strip("<>")
    return None

