from concurrent.futures import ThreadPoolExecutor, as_completed
import requests

def fetch_item(item_id: int, session: requests.Session) -> dict:
    response = session.get(f"https://api.example.com/items/{item_id}", timeout=10)
    response.raise_for_status()
    return response.json()

def fetch_all_items(item_ids: list[int]) -> list[dict]:
    results = []
    with requests.Session() as session:
        session.headers["Authorization"] = "Bearer TOKEN"
        with ThreadPoolExecutor(max_workers=10) as executor:
            futures = {executor.submit(fetch_item, id_, session): id_ for id_ in item_ids}
            for future in as_completed(futures):
                try:
                    results.append(future.result())
                except Exception as e:
                    logger.error("Failed to fetch item %s: %s", futures[future], e)
    return results

